class Solution {
public:
    vector<string> removeInvalidParentheses(string s) {
        vector<string> res;
        queue<string> q;
        bool found = false;
        set<string> visited;
        q.push(s);
        visited.insert(s);
        while (!q.empty()) {
            string t = q.front();
            q.pop();
            if (isValid(t)) {
                res.push_back(t);
                found = true;
            }
            if (found) continue;
            for (int i = 0; i < t.size(); i++) {
                if (t[i] == '(' || t[i] == ')') {
                    string tmp = t.substr(0, i) + t.substr(i + 1);
                    if (visited.find(tmp) == visited.end()) {
                        q.push(tmp);
                        visited.insert(tmp);
                    }
                }
            }
        }
        return res;
    }

    bool isValid(string s) {
        int cnt = 0;
        for (char c : s) {
            if (c == '(') cnt++;
            else if (c == ')') cnt--;
            if (cnt < 0) return false;
        }
        return cnt == 0;
    }
};
